import { TaskDell, TaskText, TaskWrapper } from "./Task.styles";

export const Task = ({todo}) => {
  const complateTask = () => {
    this.classList.toggle('complete')
  }

  return(
    <TaskWrapper onClick={complateTask}>
      <TaskText>
        {todo}
      </TaskText>
      <TaskDell>
        X
      </TaskDell>
    </TaskWrapper>
  )
}
